import { Fixture } from "../objects/fixture"

export interface FixtureProps{
    fixtures : Fixture[],
    gameType : number
}

const GetGlsAgainst = ({fixtures, gameType} : FixtureProps) => {

        return fixtures.filter(fixture => fixture.glsA).reduce((sum, fixture) => {
        if (fixture.type === gameType){
            return sum + fixture.glsA;
        }
        return sum;
    },0)}    
   
export default GetGlsAgainst;
